+//! @param wait_count Max time to wait in increments of 33 ms
+bool waitFor( const std::function<bool()> &pred, int wait_count = 10 )
+{
+  while ( --wait_count > 0 ) {
+    if ( pred() )
+      return true;
+    processEvents();
+    std::this_thread::sleep_for( 33ms );
+  }
+  return false;
+}
