+void processSomeEvents( int n = 10, int sleep_duration_us = 5000 )
+{
+  for ( int i = 0; i < n; ++i ) {
+    std::this_thread::sleep_for( std::chrono::microseconds( sleep_duration_us ) );
+    QCoreApplication::processEvents();
+  }
