+          { QVariant::ULongLong, 10000, QVariant::LongLong, -2, QVariant::LongLong, -300 },
+      };
+  for ( int i = 0; i < 4; ++i ) {
+    ASSERT_EQ( arr[i].type(), QVariant::Map );
+    QVariantMap entry = arr[i].toMap();
+    ASSERT_TRUE( entry.contains( "x" ) );
