+  // Non string in string array but can be converted to string
+  broken_map = msgToMap( msg );
+  broken_map.toMap()["strings"].value<Array>().spliceList( 3, 0, { 3456.0 } );
+  EXPECT_TRUE( fillMessage( *broken_msg, broken_map ) );
